        .main-layout {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
            max-width: 100%;
        }

        /* Table Container with Wood Border */
        .table-outer {
            padding: 22px;
            background: var(--wood-color);
            border-radius: 16px;
            box-shadow: 0 20px 50px rgba(0,0,0,0.8), 
                        inset 0 4px 10px rgba(255,255,255,0.15),
                        inset 0 -4px 10px rgba(0,0,0,0.5);
            position: relative;
            border: 4px solid #3d1d0e;
        }

        /* Diamond sights on the rails */
        .table-outer::before {
            content: '';
            position: absolute;
            top: 8px;
            left: 8px;
            right: 8px;
            bottom: 8px;
            border: 1px dashed rgba(255, 255, 255, 0.15);
            pointer-events: none;
            border-radius: 10px;
        }

        canvas {
            display: block;
            background: #165c35;
            box-shadow: inset 0 0 30px rgba(0,0,0,0.9);
            border-radius: 4px;
            cursor: crosshair;
            max-width: 100%;
            height: auto;
        }

        /* Controls & Info Panel */
        .panel {
            background: var(--panel-bg);
            border-radius: 12px;
            padding: 20px;
            width: 100%;
            max-width: 800px;
            box-sizing: border-box;
            box-shadow: 0 10px 25px rgba(0,0,0,0.5);
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 20px;
        }

        @media (max-width: 768px) {
            .panel {
